INSERT INTO Therapists(id, name, certified, image_Url, bio, location, url) VALUES
(1, 'Kezzia Quintyne-Hilaire', 'LMHC, CASAC, Counselor', 'https://res.cloudinary.com/djsguemrp/image/upload/v1739841686/kezia_hcznh7.jpg', 'My practice is dedicated to helping women of color keep their crowns on straight. My primary therapeutic focus is Eye Movement Desensitization and Reprocessing (EMDR), which uses bilateral stimulation to help replace traumatic memories.', 'Brooklyn','https://www.kqhcounseling.com/contact-black-female-therapist-nyc'),
(2, 'Keanu M. Jackson', 'Clinical Social Work/Therapist, LCSW', 'https://res.cloudinary.com/djsguemrp/image/upload/v1739844704/Keanu_anmfud.jpg', 'At the forefront of his work is an emphasis on bodily autonomy, agency, and expression as necessary components for healing and liberation.', 'Brooklyn', 'https://www.keanumjackson.com'),
(3, 'Queen Ravenden', 'Art Therapist, R-DMT, LCAT', 'https://res.cloudinary.com/djsguemrp/image/upload/v1739844706/Queen-Ravenden_rajfmt.jpg', 'I believe in healing the mind, body, spirit to achieve optimal wellness. For the mind, I use art-making (movement, visual art, creative writing, music, etc) to help you overcome low self-esteem, anxiety, past traumas, and depression.', 'Brooklyn', 'https://www.mindbodysoulvirtualwellnesscenter.com'),
(4, 'Chelsea Thornton', 'Licensed Master Social Work, LMSW', 'https://res.cloudinary.com/djsguemrp/image/upload/v1739844703/Chelsea_nmsiwd.jpg', 'As a therapist, I consider my work to be holistic, integrative, trauma-informed, and client-centered.', 'Brooklyn', 'https://www.zocdoc.com/professional/chelsea-thornton-lmsw-480442'),
(5, 'The Healing Collective', 'Clinical Social Work/Therapist, LCSW','https://res.cloudinary.com/djsguemrp/image/upload/v1739844871/Thc_adyzeb.jpg', 'We offer telehealth therapy and coaching services to individuals (youth, adolescents, and adults), couples, families, and groups throughout the state of New York and beyond', 'Brooklyn', 'https://www.thehealingcollectivepractice.com'),
(6, 'Shani Graves', 'Counselor, LMHC', 'https://res.cloudinary.com/djsguemrp/image/upload/v1739844708/Shania_mmnvbq.jpg', 'Our role at SG Wellness is to create a space for Black, Latinx and People of Color to begin exploring patterns and work towards change.', 'Brooklyn', 'https://sgcounselingnyc.com'),
(7, 'Tanner Kaleb Williams', 'Licensed Master Social Worker, LMSW', '', '', 'Manhattan', 'https://www.inclusivetherapists.com/new-york/brooklyn/tanner-williams'),
